use std::sync::{Arc, Mutex};
use std::sync::atomic::{AtomicU64, Ordering};
use std::path::Path;
use std::io::{BufReader, Read};
use std::fs::File;

#[derive(Debug)]
pub enum StoreError {
    Io(std::io::Error),
    Corrupt { offset: usize },
}

impl std::fmt::Display for StoreError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            StoreError::Io(e) => write!(f, "io: {e}"),
            StoreError::Corrupt { offset } => write!(f, "corrupt at byte {offset}"),
        }
    }
}

impl std::error::Error for StoreError {}
impl From<std::io::Error> for StoreError {
    fn from(e: std::io::Error) -> Self { StoreError::Io(e) }
}

struct Store {
    reads: AtomicU64,
    data: Arc<Mutex<Vec<u8>>>,
}

impl Store {
    fn new() -> Self {
        Store { reads: AtomicU64::new(0), data: Arc::new(Mutex::new(vec![])) }
    }

    fn load(&self, path: &Path) -> Result<(), StoreError> {
        let f = File::open(path)?;
        let mut reader = BufReader::new(f);
        let mut buf = vec![];
        reader.read_to_end(&mut buf)?;
        *self.data.lock().expect("mutex poisoned") = buf;
        Ok(())
    }

    fn read(&self, offset: usize, len: usize) -> Result<Vec<u8>, StoreError> {
        self.reads.fetch_add(1, Ordering::Relaxed);
        let data = self.data.lock().expect("mutex poisoned");
        data.get(offset..offset + len)
            .map(|s| s.to_vec())
            .ok_or(StoreError::Corrupt { offset })
    }
}
